      type?: 'Point',
      coordinates: number[]
    }
    address?: {
      city: string,
      state: string,
      street: string,
      zipcode: string
    },
    jobSites?: [Schema.Types.ObjectId]
    isActive?: boolean
    builderId: Schema.Types.ObjectId | ICompany
    customerIds: [Schema.Types.ObjectId] | Schema.Types.ObjectId
    companyId: Schema.Types.ObjectId
    inactiveAt?: Date
    inactiveBy?: Schema.Types.ObjectId | IUser
    quickbookId?: string
    createdAt?: Date
    updatedAt?: Date
}

