    },
    builderId: {
        type: Schema.Types.ObjectId,
        ref: 'Company',
        require: true
    },
    customerIds: [{
        type: Schema.Types.ObjectId,
        ref: 'Customer',
        required: true,
        select: false
    }],
    companyId: {
        type: Schema.Types.ObjectId,
    },
