import { Request, Response } from 'express';
import { Status, Messages } from '../common/constants';

import { JobSite, IJobSite } from '../models/JobSite';
import { JobLocation } from '../models/JobLocation';
import * as Sentry from '@sentry/node';
import escapeStringRegexp from 'escape-string-regexp';
import { Types } from 'mongoose';

const isProvided = (value: any): boolean => value !== undefined && value !== null && value !== '';

const getCoordinates = (params: any): { lat: any, long: any } | null => {
    const location = params?.location || {};
    const coordinates = Array.isArray(location?.coordinates) ? location.coordinates : [];
    const lat = location?.lat ?? location?.latitude ?? params?.locationLat ?? params?.lat ?? coordinates[1];
    const long = location?.long ?? location?.lng ?? location?.longitude ?? params?.locationLong ?? params?.long ?? params?.lng ?? coordinates[0];

    if (!isProvided(lat) || !isProvided(long)) {
        return null;
    }

    return { lat, long };
};

const getAddress = (params: any, existingAddress?: any): any | null => {
    const address = params?.address !== undefined
        ? params.address
        : {
            street: params?.street,
            city: params?.city,
            state: params?.state,
            zipcode: params?.zipcode
        };

    if (!address || typeof address !== 'object') {
        return null;
    }

    const addressData: any = {};
    if (isProvided(address.street)) addressData.street = address.street;
    if (isProvided(address.city)) addressData.city = address.city;
    if (isProvided(address.state)) addressData.state = address.state;
    if (isProvided(address.zipcode ?? address.zipCode)) addressData.zipcode = address.zipcode ?? address.zipCode;

    const hasAddressData = Object.values(addressData).some(isProvided);
    if (!hasAddressData) {
        return null;
    }

    return existingAddress ? { ...existingAddress, ...addressData } : addressData;
};

const getOwnershipFromJobLocation = (jobLocation: any): { customerId?: any, homeOwner?: any } => {
    const customerIds = jobLocation?.customerIds;
    const customerId = jobLocation?.customerId || (Array.isArray(customerIds) ? customerIds[0] : customerIds);
    const homeOwner = jobLocation?.homeOwner || jobLocation?.homeOwnerId;

    return {
        ...(customerId ? { customerId } : {}),
        ...(homeOwner ? { homeOwner } : {})
    };
};

const findJobLocationWithOwnership = async (locationId: string): Promise<any> => {
    const query = JobLocation.findById(locationId, {
        customerId: 1,
        customerIds: 1,
        homeOwner: 1,
        homeOwnerId: 1
    });

    if (typeof (query as any).select === 'function') {
        return (query as any).select('+customerIds customerId homeOwner homeOwnerId');
    }

    return query;
};

const isActiveValue = (value: any, currentValue: boolean): boolean => {
    if (value === undefined || value === null) {
        return currentValue;
    }

    return !(value === false || value === 'false' || value === '0');
};

export const get = async (req: Request, res: Response) => {
    const { id } = req.params;
    const { query: queryParams = {} } = req;
    const { customerId, homeOwnerId, locationId, isActive } = queryParams;

    console.log('Query Params:', queryParams);

    let query: {
        _id?: string;
        customerId?: string;
        locationId?: Types.ObjectId;
        homeOwner?: string;
        $or?: Array<{[key: string]: any}>;
        isActive?: boolean;
    } = {};

    if (id) {
        query = { _id: id };
    } else if (customerId && locationId) {
        query = { customerId, locationId: new Types.ObjectId(locationId) };
    } else if (homeOwnerId && locationId) {
        query = { homeOwner: homeOwnerId, locationId: new Types.ObjectId(locationId) };
    } else if (customerId && !homeOwnerId) {
        query = { customerId };
    } else if (customerId && homeOwnerId) {
        query = { $or: [{ customerId }, { homeOwner: homeOwnerId }] };
    } else if (homeOwnerId && !customerId) {
        query = { homeOwner: homeOwnerId };
    } else if (locationId) {
        query = { locationId: new Types.ObjectId(locationId) };
    } 

    switch (isActive) {
    case 'true':
    case true:
        query = {...query, $or: [...(query.$or || []), { isActive: true }, { isActive: { $exists: false } }] };
        break;
    case 'false':
    case false:
        query = {...query, isActive: false};
        break;
    default:
        // Retrieve all job sites
        break;
    }

    try {
        const jobSites = await JobSite.find(query).lean();
        res.status(Status.OK).json(jobSites);
    } catch (err) {
        console.error('Error in get JobSite:', err);
        res.status(Status.InternalError).json({ status: Status.Error, message: Messages.InternalServerError });
    }
};

export const create = async (req: Request, res: Response) => {
    const params = req.body || {};
    const {
        name,
        locationId
    } = params;
    const coordinates = getCoordinates(params);
    const address = getAddress(params);

    // Validate required parameters
    const missingParams = [];
    if (!name) missingParams.push('name');
    if (!locationId) missingParams.push('locationId');

    if (missingParams.length > 0) {
        const message = `${Messages.MissingParams}: ${missingParams.join(', ')}`;
        return res.status(400).json({ status: Status.Error, message });
    }

    if (!coordinates && !address) {
        return res.status(400).json({ status: Status.Error, message: 'Either location or address is required.' });
    }

    try {
        // Find the job location
        const jobLocation = await findJobLocationWithOwnership(locationId);

        if (!jobLocation) {
            return res.status(404).json({ status: Status.Error, message: 'Subdivision not found.' });
        }

        const existingJobSite = await JobSite.findOne({ locationId, name }).lean();
        if (existingJobSite) {
            return res.status(400).json({ status: Status.Error, message: 'Job Address already exists in this subdivision.' });
        }

        const newJobSiteData: any = {
            name,
            address,
            locationId,
            ...getOwnershipFromJobLocation(jobLocation)
        };

        if (coordinates) {
            newJobSiteData.location = {
                coordinates: [coordinates.long, coordinates.lat]
            };
        }

        // Create the new job site
        const newJobSite: IJobSite = await JobSite.create(newJobSiteData);

        // Update the job location with the new job site
        await JobLocation.findByIdAndUpdate(locationId, {
            $push: { jobSites: newJobSite._id }
        });

        return res.status(Status.OK).json(newJobSite);

    } catch (error) {
        Sentry.captureException(error);
        console.error('Error in create job site:', error);
        return res.status(500).json({ status: Status.Error, message: Messages.InternalServerError });
    }
};

export const update = async (req: Request, res: Response) => {
    const params = req.body || {};
    const { id } = req.params;
    const {
        name,
        isActive,
        locationId,
    } = params;

    const missingParams = [];
    if (!id) missingParams.push('id');
    const isMissingParams = missingParams.length > 0;

    if (isMissingParams) {
        const message = `${Messages.MissingParams}: ${missingParams.join(', ')}`;
        return res.json({ status: Status.Error, message });
    }

    try {
        const jobSite: any = await JobSite.findById(id).exec();
        if (!jobSite) {
            return res.json({ status: Status.Error, message: 'Job Address not found.' });
        }

        const effectiveLocationId = locationId || jobSite.locationId;
        let jobLocation = null;

        if (locationId) {
            jobLocation = await findJobLocationWithOwnership(locationId);
            if (!jobLocation) {
                return res.json({ status: Status.Error, message: 'Subdivision not found.' });
            }
        }

        const shouldCheckDuplicateName = isProvided(name)
            && (name !== jobSite.name || String(effectiveLocationId) !== String(jobSite.locationId));
        if (shouldCheckDuplicateName) {
            const duplicateJobSite = await JobSite.findOne({
                _id: { $ne: id },
                locationId: effectiveLocationId,
                name
            }).lean();

            if (duplicateJobSite) {
                return res.status(400).json({ status: Status.Error, message: 'Job Address already exists in this subdivision.' });
            }
        }

        const updateData: any = {};
        const coordinates = getCoordinates(params);
        const address = getAddress(params, jobSite.address);

        if (isProvided(name)) {
            updateData.name = name;
        }

        if (coordinates) {
            updateData.location = {
                ...(jobSite.location?.type ? { type: jobSite.location.type } : {}),
                coordinates: [coordinates.long, coordinates.lat]
            };
        }

        if (address) {
            updateData.address = address;
        }

        if (locationId) {
            updateData.locationId = locationId;
            Object.assign(updateData, getOwnershipFromJobLocation(jobLocation));
        }

        if (isActive !== undefined && isActive !== null) {
            updateData.isActive = isActiveValue(isActive, jobSite.isActive);
        }

        if (Object.keys(updateData).length === 0) {
            return res.json({ status: Status.OK, message: 'Job Address has been updated successfully.' });
        }

        await JobSite.updateOne({ _id: id }, { $set: updateData });
        return res.json({ status: Status.OK, message: 'Job Address has been updated successfully.' });
    } catch (err) {
        Sentry.captureException(err);
        console.error('Error in update job site:', err);
        return res.json({ status: Status.Error, message: Messages.InternalServerError });
    }
};




